var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>《프로젝트 테라사이드 제 4차 실험 보고서》</color>","JPN":"<color=#ffd34c>《プロジェクト・テラサイド、第4次実験報告書》</color>","ENG":"<color=#ffd34c>《Project Terraside - 4th experiment report》</color>","TWN":"<color=#ffd34c>《特拉賽德專案第4次實驗報告書》</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이터니움을 베이스로 한 나노 변이 인자 테스트는 성공적.</color>","JPN":"<color=#ffd34c>エタニウムをベースとしたナノ変異ファクターテストは成功。</color>","ENG":"<color=#ffd34c>The Eternium-based nano mutation factor test was a success.</color>","TWN":"<color=#ffd34c>以永恆之金為基礎的納米變異因子試驗成功。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최초 변이 시에는 외부에서 인자를 공급해야 하지만 이후 육체의 대사기능을 전용하여 변이 인자의 자가복제, 재생산이 가능.</color>","JPN":"<color=#ffd34c>初変異の際に、外部からファクターを供給しなければならないが、\\n以降は肉体の代謝機能を転用し、変異ファクターの自己複製や再生産が可能。</color>","ENG":"<color=#ffd34c>Although the factors must be provided from outside for the initial mutation phase, the mutation factors can duplicate and reproduce themselves using the host's metabolic system afterwards.</color>","TWN":"<color=#ffd34c>雖然在最初變異時，需要從外部供給因子，但是之後可以指定肉體的代謝機能，使變異因子能夠自我複製、再生產。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>재생산된 변이 인자의 고밀도집속 및 재설계를 통해 【최종 변이 인자】 제작 가능성 확인.</color>","JPN":"<color=#ffd34c>再生産された変異ファクターの高密度集束および再設計により\\n【最終変異ファクター】の製作可能性を確認。</color>","ENG":"<color=#ffd34c>This confirms the viability of creating the 【Ultimate Mutation Factors】 through high-density integration and redesign of reproduced mutation factors.</color>","TWN":"<color=#ffd34c>通過再生產出來的變異因子高密度集聚和再設計，確認可以製作【最終變異因子】。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>단, 충분한 양의 변이 인자를 시간 내에 생산하기 위한 특단의 대책 필요.</color>","JPN":"<color=#ffd34c>ただし、十分な量の変異ファクターを期限内に生産するための特段の対策が必要。</color>","ENG":"<color=#ffd34c>However, a special measure is required to ensure better mutation factor production efficiency.</color>","TWN":"<color=#ffd34c>只是，要在時間內生產足量的變異因子需要使用特別的對策。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현 추세대로 진행될 경우 잔여 생존 인류 절멸까지 약......</color>","JPN":"<color=#ffd34c>現在の傾向が続く場合、残りの生存人類の絶滅まで約……</color>","ENG":"<color=#ffd34c>Considering the speed of progression, the estimated time until the complete extinction of the remaining population is...</color>","TWN":"<color=#ffd34c>按照現在的趨勢進行下去，剩下的人類離滅絕大約……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서, 선배?!","JPN":"せ、先輩！？","ENG":"Sh-Shiyoon?","TWN":"前、前輩？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>데이터를 삭제하시겠습니까?</color>","JPN":"<color=#ffd34c>データを削除しますか？</color>","ENG":"<color=#ffd34c>Do you want to delete the data?</color>","TWN":"<color=#ffd34c>要刪除資料嗎？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>Yes</color>","JPN":"<color=#ffd34c>Yes</color>","ENG":"<color=#ffd34c>Yes</color>","TWN":"<color=#ffd34c>Yes</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>데이터가 모두 삭제되었습니다.</color>","JPN":"<color=#ffd34c>データがすべて削除されました。</color>","ENG":"<color=#ffd34c>All data has been deleted.</color>","TWN":"<color=#ffd34c>資料已全部刪除。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이런 곳에 있었어?","JPN":"こんなところにいたの？","ENG":"I didn't expect to meet you here.","TWN":"你怎麼會在這種地方？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 미나 양.","JPN":"あ、ミナさん。","ENG":"Oh, Mina.","TWN":"啊，米娜小姐。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다행이네요. 이러다 꼼짝없이 혼자 미아가 되는 게 아닌가 했었거든요.","JPN":"よかったです、このまま一人ぼっちで迷子になるんじゃないかと思いました。","ENG":"Thank goodness. I was lost out there alone and thought I'd be lost forever.","TWN":"真是太好了呢。我還以為再這樣下去，我就要迷路了呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"일행들을 찾다가 뉴 오하이오가 대파되는 모습을 보고 여기로 왔는데......","JPN":"捜索中にニューオハイオが大破するのを見かけたので、ここに来たのですが……","ENG":"I saw the New Ohio sink while looking all over for allies and headed here.","TWN":"我在尋找同伴的時候，發現新俄亥俄被破壞了，所以就過來看看……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여기서 미나 양을 만나게 되다니, 역시 이게 정답이었나 보네요. 하하.","JPN":"ここでミナさんと落ち合えたので、やっぱりこれが正解だったみたいですね、ハハ。","ENG":"You being here proves I made the right move, Hah hah.","TWN":"結果竟然能在這裡遇到米娜小姐，看來我來這裡是正確的決定呢。哈哈。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그보다 온몸이 피투성이잖아? 괜찮은 거야?","JPN":"そ、それより、全身が血だらけじゃない？　大丈夫なの？","ENG":"B-but you have blood all over you! What happened?","TWN":"話，話說你全身都是血耶？你沒事嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아아...... 이거 말인가요?","JPN":"ああ……これのことですか？","ENG":"Ah, this?","TWN":"啊啊……妳說這個嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건 그러니까...... 오는 길에 괴물과 마주쳐서 말이죠.","JPN":"これはですね……道中でバケモノに出くわしてしまって。","ENG":"This is... Well, I ran into a monster on the way here.","TWN":"這是因為……我在來的路上碰到了怪物。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괴, 괴물?","JPN":"ば、バケモノ？","ENG":"M-monster?","TWN":"怪、怪物？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네, 엄청난 괴물이었죠.","JPN":"ええ、ものすごいバケモノでした。","ENG":"Yes, a very scary monster.","TWN":"沒錯，很可怕的怪物。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괴물이라니......? 고위 침식체라도 만난 거야?","JPN":"何それ……？　高位侵食体にでも出くわしたの？","ENG":"What monster? Did you run into a high-level C.O.?","TWN":"你說怪物……？是遇到高等侵蝕體嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐 그 비슷한 겁니다. 어쨌든 지금은 간신히 도망쳐 왔으니 신경 쓰지 않아도 돼요.","JPN":"まあ、似たようなもんです。\\nとにかく、やっとのことで逃げ出してきたので、気にしなくても大丈夫です。","ENG":"You could say that. Well, I managed to run away, so you don't have to worry.","TWN":"嗯，差不多吧。反正我總算是逃掉了，不用擔心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래......? 그렇다면 뭐......","JPN":"そうなの……？　それなら、まあ……","ENG":"Yeah? Well, o-okay, if you say so...","TWN":"是嗎……？那就好……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 조금 전에 보니까 뭘 읽고 있는 것 같던데? 그건 뭐야?","JPN":"ところで、さっき何かを読んでいたみたいだけど、それは何？","ENG":"I noticed you were reading something there. What is it?","TWN":"話說回來，剛剛你好像在看什麼東西的樣子，那是什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 이건...... 뉴 오하이오에 들어온 김에 리플레이서의 데이터 뱅크 자료를 조금 찾아보고 있었어요.","JPN":"あ、これは……ニューオハイオに入ったついでに、\\nリプレイサーのデータバンクの資料を調べていました。","ENG":"Ah, this? I was looking into the Replacers' data bank.","TWN":"啊，這個啊……既然進到了新俄亥俄裡面，我就順便看了一下克隆集團資料庫裡的資料。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여긴 처음이니까 리플레이서의 정보라든가 뉴 오하이오의 구조라도 알아보면 좋을 것 같아서요.","JPN":"初見ですし、リプレイサーの情報やニューオハイオの構造だけでも調べられたらと思って。","ENG":"Since this is my first time being inside the New Ohio, I thought it'd be a good idea to find information about the Syndicate or the base structure of the ship.","TWN":"我是第一次來這裡，瞭解一下克隆集團的資訊或者新俄亥俄的構造還是不錯的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 뭔가 좋은 정보라도 있었어?","JPN":"そうなのね、何か良い情報でもあった？","ENG":"Yeah? Did you find anything useful?","TWN":"是嗎？那有什麼不錯的情報嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 글쎄요. 아쉽게도 별 건 없었네요.","JPN":"ハハ、どうでしょう。残念ながら、大してないですね。","ENG":"Hah hah, unfortunately, there was nothing I could make use of.","TWN":"哈哈，這個嘛。很可惜，沒有特別發現什麼東西。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그보다 이상한 게 있어요, 미나 양.","JPN":"ミナさん、それよりも妙なことが……","ENG":"But don't you think it's weird, Mina?","TWN":"不過好像有點奇怪呢，米娜小姐。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이상한 거?","JPN":"妙なこと？","ENG":"Weird?","TWN":"奇怪？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 제가 여기에 들어온 이후로 리플레이서 병력들과는 전혀 마주친 적이 없어서요.","JPN":"はい、僕がここに入って以来、リプレイサーの兵士とまったく出くわしていないんです。","ENG":"Yes. I haven't run into a single Replacer unit since I came in here.","TWN":"是的。我進到這裡卻完全沒有遇到克隆集團的兵力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저, 정말이야? 운이 좋은 건가?","JPN":"ほ、本当？　運がいいのかな？","ENG":"R-really? You must be very lucky!","TWN":"真，真的嗎？太幸運了吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 뭐 그럴 수도 있겠지만......","JPN":"ハハ、まあ、その可能性もあるでしょうけど……","ENG":"Hah hah, I guess you could say that, but...","TWN":"哈哈，是有可能啦……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇다고 해도 이런 거대한 함선을 운용하려면 최소한의 승무원들이라도 있어야 할 텐데, 아무런 인기척이 없다는 건 부자연스럽지 않나요?","JPN":"こんな巨大な艦船を動かすには、少なくとも乗務員はいて当然だと思うのですが、\\nまったく人影がないのは不自然じゃありませんか？","ENG":"Doesn't it feel unnatural that there's not a single crewmember keeping busy in a ship this big?","TWN":"但就算這麼說，像這種巨大的艦船上，最少也該有乘務員吧，沒有人聲氣息未免太不自然了？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어? 듣고 보니......","JPN":"あれ、そう言われてみれば……","ENG":"Err? Come to think of it...","TWN":"咦？聽你這麼一說……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건 마치...... 말로만 듣던 유령선 같군요.","JPN":"これじゃ、まるで……幽霊船みたいです。","ENG":"This looks like the ghost ships I've read about in stories...","TWN":"這就好像……傳聞中的幽靈船一樣呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무, 무서운 소리 하지 마!","JPN":"お、恐ろしいこと言わないで！","ENG":"Y-you're scaring me!","TWN":"別、別說些嚇人的話啦！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 유령을 무서워할 줄은 몰랐네요, 하하.","JPN":"ミナさんが幽霊を怖がるとは、ハハ。","ENG":"Hah hah! I never knew you were afraid of ghosts.","TWN":"我都不知道米娜小姐會害怕幽靈呢，哈哈。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그보다 미나 양은 왜 여기에 오신 거죠?","JPN":"それより、ミナさんはどうしてこちらに？","ENG":"But Mina, what are you here for?","TWN":"話說米娜小姐為什麼會來這裡？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"혼자서 급하게 달려온 것 같은데...... 뭔가 임무라도 맡으신 건가요?","JPN":"一人で急いで駆け付けたようですが……何か任務ですか？","ENG":"You came here in a hurry, all by yourself. Are you on a mission?","TWN":"妳似乎是一個人趕過來的……是接到了什麼任務嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으응, 사실은 소대장이 리플레이서 퀸을 상대하는 동안 나에게 테라사이드 시스템의 중추를 파괴하라고 했어.","JPN":"ううん、実は小隊長がリプレイサー・クイーンを相手してる間、\\n私にテラサイドシステムの中枢を破壊しろって。","ENG":"Well, actually, Commander told me to go destroy the backbone of System Terraside while she fights the Replacer Queen,","TWN":"唔嗯，其實是小隊長在對付克隆．女皇的時候，要我來破壞特拉賽德系統的中樞。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇지 않으면 리플레이서 퀸을 쓰러트려도 계속 재생하니까.","JPN":"そうしないと、リプレイサー・クイーンを倒したところで再生し続けるだろうから。","ENG":"so that the Replacer Queen would stop regenerating.","TWN":"不然就算打倒了克隆．女皇，她也會不斷地再生。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"테라사이드 시스템의 중추?","JPN":"テラサイドシステムの中枢？","ENG":"The backbone of System Terraside?","TWN":"特拉賽德系統的中樞？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래, 아마도 불멸체 코어인가 하는 걸 말하는 것 같아.","JPN":"そう、たぶん不滅体コアとやらのことみたい。","ENG":"Yeah, I'm guessing she was talking about that Immortal System Core thing.","TWN":"對，大概是指不滅者核心吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음...... 글쎄요.","JPN":"ふむ……どうでしょう。","ENG":"Hmm... You think?","TWN":"哼嗯……這難說喔。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배? 표정이 이상한데? 내가 무슨 틀린 말이라도 했어?","JPN":"先輩？　変な顔してるよ？　私、何か間違ったこと言った？","ENG":"Shiyoon? You look odd. Did I say anything wrong?","TWN":"前輩？你表情很怪耶？我說錯了什麼話嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 아무것도 아닙니다, 하하.","JPN":"な、何でもないです、ハハ。","ENG":"Hah hah, no, it’s nothing.","TWN":"啊，沒什麼，哈哈。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그보다 불멸체 코어라면 아마 대량의 에너지 교환이 가능한 기관실에 있을 겁니다.","JPN":"それより、不滅体コアなら大量のエネルギー交換が可能な機関室にあるはずです。","ENG":"The Immortal System Core must be in the engine room, where it can process the massive energy exchange.","TWN":"不過不滅者核心的話，應該在能夠進行大量能量交換的機關室裡吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여기서 멀지 않아요. 빨리 가보죠.","JPN":"ここから遠くないですよ、さっそく行ってみましょう。","ENG":"It's not too far from here. Let's go.","TWN":"離這裡不遠。快去看看吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래!","JPN":"うん！","ENG":"Okay!","TWN":"是！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};